import {Button, Col, Row} from "react-bootstrap";
import {t} from 'ftc-common/i18n';

import * as api from './api/allianceSelection';

import './AllianceSelection.css'
import {showAllianceSelection} from "./api/display";
import {SelectionMethod, SelectionOp, SelectionState} from "ftc-common/javaTypes";
import {EventSettings, Match, MatchType} from "../javaTypes";
import {confirmDialog, messageDialog, promptDialog} from "first-common/dialogs";
import {Temporal} from "temporal-polyfill";
import {useState} from "react";

const tableButtonAttrs = {
    className: 'btn-xs',
    variant: 'light'
} as const

export default function AllianceSelection({matches, eventCode, selectionState, activeType, settings}: {
    matches: Match[],
    eventCode: string,
    selectionState?: SelectionState,
    activeType: MatchType,
    settings: Partial<EventSettings>
}) {
    const [targetAlliance, setTargetAlliance] = useState<number | null>(null);

    // TODO finish backporting this from CRI
    // The even slots (until each alliance has made their first pick) are captain slots, and there is no active acceptance
    // required for them, so pre-label them as captains
    const isBackupOnly = activeType == MatchType.ELIMS
    const isCaptainSlot = !isBackupOnly && selectionState && [...Array(selectionState.alliances.length).keys()].map(x => x * 2).includes(selectionState?.nextSlot)
    const nextCaptain = selectionState?.teams?.find(t => !t.removed && !t.captain && !t.picked)
    let disabledSlots = selectionState?.teams?.map((team) => {
        if(team.removed) {
            return t`Unavailable`
        } else if(team.picked) {
            return t`Selected`
        } else if(team.captain) {
            return t`Captain`;
        } else if(isCaptainSlot && team.number === nextCaptain?.number) {
            return t`Next Captain`
        } else if(team.declined) {
            return t`Unavailable - declined`
        } else {
            return false;
        }
    }) || []

    const teamCount = selectionState ? selectionState.teams.length : 0

    async function startSelection() {
        const unplayedMatches = matches.filter(m => m.state !== "COMMITTED").length
        if(unplayedMatches > 0){
            if(!await confirmDialog({
                label: t`Start Alliance Selection?`,
                text: t`WARNING: There are ${unplayedMatches} un-committed matches. Any Qualification matches committed after starting alliance selection will NOT be considered in the rankings used during Alliance Selection.`,
                buttonText: t`Start`})) {
                    return;
            }
        }

        const startTime = await promptDialog({
            label: 'Playoff Match Start Time',
            text: 'Enter the time the first playoff match is expected to start',
            customInputParams: {
                type: 'datetime-local',
                step: 300
            },
            defaultValue: Temporal.Now.plainDateTimeISO().add({minutes: 30}).round({ roundingIncrement: 5, roundingMode: 'ceil', smallestUnit: 'minute' }).toString().slice(0, 16),
            buttonText: 'Submit'
        })
        if(!startTime) {
            return;
        }

        const newState = await api.startSelection(eventCode, startTime)
        if(!newState) {
            messageDialog({
                label: t`Failed to Start Selection`,
                text: t`Starting Selection Failed.`
            })
        }
    }

    async function submitSelection(team: number, type: SelectionOp) {
        const newState = await api.submitSelection(eventCode, team, type, SelectionMethod.CONTROL)
        if(!newState) {
            messageDialog({
                label: t`Failed to Submit Selection`,
                text: t`Selection Submission Failed.`
            })
        }
    }

    async function undoSelection() {
        const selectionState = await api.undoSelection(eventCode)
        if(!selectionState) {
            messageDialog({
                label: t`Failed to Submit Selection`,
                text: t`Selection Undo Failed.`
            })
        }
    }

    async function finishSelection() {
        let confirmationWarning = null;
        const availableCount = selectionState!.teams.filter(x => !x.declined && !x.removed && !x.captain && !x.removed).length;
        if(selectionState!.alliances.some(a => !a[1])) {
            if (availableCount > 1) {
                // if available count is 1, then the only team left is the currently selecting captain. Don't show the warning
                confirmationWarning = t`Alliances are not full (2 Teams each).`;
            }
        } else if (selectionState!.teamsPerAlliance > 2 && selectionState!.nextSlot < 12) {
            confirmationWarning = t`Alliances are not full (3 Teams each).`;
        }

        if(confirmationWarning && !await confirmDialog({
                label: t`Finish Alliance Selection?`,
                text: t`WARNING: ${confirmationWarning} Are you sure you want to generate Elimination Matches with these alliances?`,
                buttonText: t`Generate`
            })) {
            return;
        }

        const startTime = await promptDialog({
            label: 'Playoff Match Start Time',
            text: 'Confirm the time the first playoff match is expected to start',
            customInputParams: {
                type: 'datetime-local',
                step: 300
            },
            defaultValue: selectionState!.playoffStartTime,
            buttonText: 'Submit'
        })
        if(!startTime) {
            return;
        }

        if(!await api.finishSelection(eventCode, startTime)) {
            messageDialog({
                label: t`Failed to Generate Elimination Matches`,
                text: t`Unable to complete alliance selection.`
            })
        }
    }

    async function addBackup(seed: number, team: number) {
        if(await api.addBackup(eventCode, seed, team)) {
            setTargetAlliance(null)
        } else {
            messageDialog({
                label: t`Failed to Submit Backup`,
                text: t`Backup Selection Failed.`
            })
        }
    }

    async function removeBackup(seed: number) {
        if(!await confirmDialog({
            label: t`Remove Backup Team`,
            text: t`Backup teams should only be removed if they were added in error and have not played in a match yet.`,
            buttonText: t`Remove`
        })) {
            return;
        }

        try {
            if (!await api.removeBackup(eventCode, seed)) {
                messageDialog({
                    label: t`Failed to Remove Backup`,
                    text: t`Backup Removal Failed.`
                })
            }
        } catch (e: any) {
            messageDialog({
                label: t`Failed to Remove Backup`,
                text: e.message || t`Backup Removal Failed.`
            })
        }
    }

    const matchStartTime = selectionState ? Temporal.PlainDateTime.from(selectionState.playoffStartTime).toPlainTime().toLocaleString(undefined, { timeStyle: 'short' }) : null;

    let overrideString = "";
    if (settings.allianceCountOverride) {
        overrideString += settings.allianceCountOverride + " alliances";
    }
    if (settings.teamsPerAllianceOverride) {
        if (settings.allianceCountOverride) overrideString += " of " + settings.teamsPerAllianceOverride + " teams";
        else overrideString = settings.teamsPerAllianceOverride + "-team alliances"
        if (settings.allowBackupsOverride) {
            overrideString += " + backups"
        }
    }
    if (settings.playoffTypeOverride) {
        const prefix = overrideString.length ? " in " : "";
        switch (settings.playoffTypeOverride) {
            case "DOUBLE_ELIMINATION_WITH_FINALS": overrideString += prefix + "double elimination with finals"; break;
            case "SINGLE_ELIMINATION": overrideString += prefix + "single elimination"; break;
        }
    }

    return <div className={"container-fluid"}>
        <Row>
            <Col>
                <div className={"mx-auto"} style={{width: 'fit-content'}}>
                    { activeType === 'ELIMS' ? <div className={"mb-2"}>
                        <h3>{t`Backup Team Selection`}</h3>
                        {targetAlliance
                            ? <>
                                {t`Adding a backup team to Alliance ${targetAlliance}`} <Button variant={"primary"} size={"sm"} onClick={() => setTargetAlliance(null)}>{t`Cancel`}</Button></>
                            : null}
                    </div> : <>
                        <Button className={"m-2"} variant={selectionState ? 'light' : 'success'} disabled={!!selectionState} onClick={startSelection}>{t`Start Alliance Selection`}</Button>
                        <Button className={"m-2"} variant='success' onClick={() => showAllianceSelection(eventCode)}>{t`Set Audience Display`}</Button>
                    </>}
                </div>
            </Col>
        </Row>
        <Row>
            <Col sm="4">
                {overrideString ? <div className={"alert alert-warning text-center"}>Elimination Override: {overrideString}</div> : null}
                <table className={"alliancesTable mx-auto"}>
                    <thead>
                        <tr>
                            <th>{t`Alliance`}</th>
                            <th>{t`Captain`}</th>
                            {(selectionState?.teamsPerAlliance || 0) > 2 ? <>
                                <th>{t`1st Pick`}</th>
                                <th>{t`2nd Pick`}</th>
                            </>: <th>{t`Partner`}</th>}
                        </tr>
                    </thead>
                    <tbody>
                        {selectionState?.alliances.map((a, aidx) => <tr key={aidx}>
                            <th>{aidx+1}</th>
                            {a.map((t, idx) => <td key={idx}>
                                {selectionState.teams.find(t2 => t2.number == t)?.displayNumber}
                                {isBackupOnly && idx == 2 ? ((t ? <><br /><Button {...tableButtonAttrs} variant={"danger"}
                                                                                  onClick={() => removeBackup(aidx + 1)}>Remove</Button></>
                                    : <Button {...tableButtonAttrs} variant={"outline-warning"} disabled={!!t}
                                              onClick={() => setTargetAlliance(aidx + 1)}>Add Backup</Button>)) : null}
                            </td>)}
                        </tr>)}
                    </tbody>
                </table>
                {isBackupOnly ? null : <div className={"mx-auto"} style={{width: 'fit-content'}}>
                    <Button className={"m-2"} variant={!selectionState ? 'light' : 'success'} disabled={!selectionState} onClick={undoSelection}>{t`Undo`}</Button>
                    <Button className={"m-2"} variant={!selectionState ? 'light' : 'success'} disabled={!selectionState} onClick={finishSelection}>{t`Generate Matches`}</Button>
                </div>}
                <div className={"mx-auto text-center"}>
                    <span>{matchStartTime && !isBackupOnly ? t`Playoff matches begin at ${matchStartTime}` : null}</span>
                </div>
            </Col>
            <Col sm="8">
                <table className={"alliancesTable mx-auto"}>
                    <thead>
                        <tr>
                            <th>{t`Rank`}</th>
                            <th>{t`Number`}</th>
                            <th>{t`Name`}</th>
                            <th style={{width: '100px'}}>{t`Select`}</th>
                            {isBackupOnly ? null : <>
                                <th style={{width: '100px'}}>{t`Decline`}</th>
                                <th style={{width: '100px'}}>{t`Remove`}</th>
                            </>}
                        </tr>
                    </thead>
                    <tbody>
                        {selectionState?.teams?.map((team, idx) => <tr key={team.number}>
                            <th>{team.rank}</th>
                            <td>{team.displayNumber}</td>
                            <td>{team.name}</td>
                            {disabledSlots[idx] || (isBackupOnly ? !targetAlliance : (selectionState.nextSlot >= (selectionState.alliances.length * selectionState.teamsPerAlliance))) ? <td colSpan={isBackupOnly ? 1 : 2}>{disabledSlots[idx]}</td> : <>
                                <td>
                                    <Button {...tableButtonAttrs}
                                            onClick={async () => {
                                                isBackupOnly && targetAlliance ? await addBackup(targetAlliance, team.number) : await submitSelection(team.number, SelectionOp.ACCEPT)
                                            }}>
                                        {t`Accept`}
                                    </Button>
                                </td>
                                {isBackupOnly ? null : <td>
                                    <Button {...tableButtonAttrs}
                                            onClick={() => submitSelection(team.number, SelectionOp.DECLINE)}>
                                        {t`Decline`}
                                    </Button>
                                </td>}
                            </>}
                            {team.removed || (disabledSlots[idx] && (!isCaptainSlot || team.number !== nextCaptain?.number)) || isBackupOnly ? null : <td>
                                <Button {...tableButtonAttrs}
                                        onClick={() => submitSelection(team.number, SelectionOp.REMOVE)}
                                        title="Use if e.g. the team has left the venue">
                                    {t`Remove`}
                                </Button>
                            </td>}
                        </tr>)}
                    </tbody>
                </table>

            </Col>
        </Row>
    </div>
}
