export type DisplayDataWithConfig = DisplayData & {data: DisplayConfig};

function DisplaysTable({eventCode, displayData, fieldCount, showMeetRankings, isDualDivisionParent, divisions}: {
    eventCode: string,
    displayData: DisplayDataWithConfig[],
    fieldCount: number,
    showMeetRankings: boolean,
    isDualDivisionParent: boolean,
    divisions: string[]
}) {
    const [selectedDisplay, setSelectedDisplay] = useState<DisplayDataWithConfig>();
    const [sortedDisplays, setSortedDisplays] = useState<DisplayDataWithConfig[]>([]);
    const [checkedDisplays, setCheckedDisplays] = useState<string[]>([]);
    const [showBulkReconfigure, setShowBulkReconfigure] = useState(false);
    const [bulkDivision, setBulkDivision] = useState(0);
    const [bulkField, setBulkField] = useState(0);
    useEffect(() => {
        // If the display being configured DCs, close the dialog.
        if (selectedDisplay && !displayData.some(d => d.id === selectedDisplay?.id)) {
            setSelectedDisplay(undefined);
        }
    }, [selectedDisplay, displayData]);

    useEffect(() => {
        setSortedDisplays([...displayData].sort((a, b) => {
            if(a.division != b.division) {
                return a.division - b.division;
            } else if(a.data.name !== b.data.name) {
                const aName = a.data.name
                const bName = b.data.name
                if(aName && !bName) {
                    return 1;
                } else if(!aName && bName) {
                    return -1;
                } else if(aName && bName) {
                    return aName.localeCompare(bName)
                } else {
                    return 0;
                }
            } else {
                return a.id.localeCompare(b.id)
            }
        }))
    }, [displayData]);
    const typeMap = {
        audience: t`Audience`,
        field: t`Field`,
        cmpBar: t`Banner`,
        pit: t`Pit`,
        sponsor: t`Sponsors`
    }
    const row = (data: DisplayDataWithConfig) => {
        let config = data?.data;
        if (!config) {
            return null;
        }
        const configBtn = <button className={"btn btn-info btn-sm"} onClick={() => setSelectedDisplay(data)}>{t`Config`}</button>
        const divisionDisplay = data.division ? divisions[data.division - 1] : t`Parent`;
        const intro = <>
            <td><input type="checkbox"
                       checked={checkedDisplays.includes(data.id)}
                       onChange={(e) => {
                           if ((e.target as HTMLInputElement).checked) {
                               setCheckedDisplays([...checkedDisplays, data.id]);
                           } else {
                               setCheckedDisplays(checkedDisplays.filter(ip => ip !== data.id));
                           }
                       }}
            /></td>
            <td>{data.ip}</td>
            {isDualDivisionParent ? <td>{divisionDisplay}</td> : null}
            <td>{config.name}</td>
            <td>{typeMap[config.type]}</td>
        </>
        if (config.type === "pit" || config.type === "sponsor") {
            return <tr>{intro}<td></td><td></td><td></td><td></td><td></td><td>{configBtn}</td></tr>
        }
        // TODO maybe warning icon if >1 on same IP unmuted?
        return <tr key={data.id}>
            {intro}
            <td>{config.bindToField === "all" ? t`All` : config.bindToField}</td>
            <td>{config.overlay ? t`Overlay` : (config.fieldStyleTimer ? t`Field` : t`Audience`)}</td>
            <td>{config.mute ? t`Off` : t`On`}</td>
            <td>{config.scoringBarLocation === "bottom" ? t`Bottom` : t`Top`}</td>
            <td>{config.allianceOrientation === "standard" ? t`Standard (Red on Left)` : t`Flipped (Red on Right)`}</td>
            <td>{configBtn}</td>
        </tr>
    }

    function sendBulkUpdate() {
        api.bulkReconfigure(eventCode, checkedDisplays, bulkDivision, bulkField);
        setCheckedDisplays([]);
        setShowBulkReconfigure(false);
    }

    return <>
        <table style={{width: "100%", textAlign: "center"}}>
            <thead>
            <tr style={{borderBottom: "1px solid white"}}>
                <th></th>
                <th>{t`IP`}</th>
                {isDualDivisionParent ? <th>{t`Division`}</th> : null}
                <th>{t`Name`}</th>
                <th>{t`Type`}</th>
                <th>{t`Field`}</th>
                <th>{t`Timer Style`}</th>
                <th>{t`Audio`}</th>
                <th>{t`Scoring Bar`}</th>
                <th>{t`Alliance Orientation`}</th>
                <th>{t`Config`}</th>
            </tr>
            </thead>
            <tbody>
            {sortedDisplays.map((d) => row(d))}
            </tbody>
        </table>
        <Button className={"mr-2"} variant={"primary"} size={"sm"} disabled={checkedDisplays.length == 0} onClick={() => setShowBulkReconfigure(true)}>{t`Bulk Reconfigure`}</Button>
        {isDualDivisionParent ? <>
            <Button className={"mr-2"} variant={"secondary"} size={"sm"} onClick={() => setCheckedDisplays(sortedDisplays.map(d => d.id))}>{t`Select All`}</Button>
            <Button className={"mr-2"} variant={"secondary"} size={"sm"} onClick={() => setCheckedDisplays([])}>{t`Clear Selection`}</Button>
        </>: null}
        {selectedDisplay?.data ?
        <ConfigDialog show={!!selectedDisplay} handleClose={() => setSelectedDisplay(undefined)} fieldCount={selectedDisplay.division ? 2 : (fieldCount || 1)}
                      config={selectedDisplay?.data} setConfig={(cfg) => {
                            setSelectedDisplay(Object.assign({}, selectedDisplay, {data: cfg}))
                            api.setConfig(eventCode, selectedDisplay.id, cfg);
                      }} isDualDivisionParent={isDualDivisionParent && !selectedDisplay.division} style={"default"} showMeetRankings={showMeetRankings} remoteConfig={true}/>
            : null}
        <Modal show={showBulkReconfigure} onHide={() => setShowBulkReconfigure(false)}>
            <Modal.Header closeButton>
                <Modal.Title>Reconfigure Multiple Displays</Modal.Title>
            </Modal.Header>

            <Modal.Body>
                <Row>
                {isDualDivisionParent ? <>
                  <Form.Label column sm="4">{t`Division`}</Form.Label>
                  <Col sm="8">
                      <Form.Control as="select" custom value={bulkDivision} onChange={e => setBulkDivision(parseInt(e.target.value))}>
                            <option value={0}>{t`Parent`}</option>
                            {divisions.map((d, i) => <option key={i} value={i + 1}>{d}</option>)}
                      </Form.Control>
                  </Col>
                </>: null}
                <Form.Label column sm="4">{t`Bind to Field`}</Form.Label>
                <Col sm="8">
                    <Form.Control as="select" custom value={bulkField} onChange={e => setBulkField(parseInt(e.target.value))}>
                        <option value={0}>{t`(All)`}</option>
                        {[...Array(bulkDivision ? 2 : (fieldCount || 1)).keys()].map(i => {
                            const fieldNo = i + 1;
                            return <option key={fieldNo} value={fieldNo}>{t`Field ${fieldNo}`}</option>
                        })}
                    </Form.Control>
                </Col>
                </Row>
            </Modal.Body>

            <Modal.Footer>
                <Button variant="secondary" onClick={() => setShowBulkReconfigure(false)}>Close</Button>
                <Button variant="primary" onClick={() => sendBulkUpdate()}>Update Display</Button>
            </Modal.Footer>
        </Modal>
    </>
}

function VideoUpdater() {
    const [updateProgress, setUpdateProgress] = useState<undefined | number>(undefined);
    const [updateStatusText, setUpdateStatusText] = useState("");
    const queryClient = useQueryClient();

    async function updateVideos() {
        setUpdateProgress(undefined);
        setUpdateStatusText(t`Starting update...`);
        if(!await downloadVideos()) {
            setUpdateStatusText("Failed to start video download.");
            return;
        }
        const ws = new WebSocket(`${window.location.protocol === "https:" ? "wss" : "ws"}://${window.location.host}/stream/manage/video_download/status/`);
        ws.onmessage = function(evt) {
            const msg = JSON.parse(evt.data);
            if(msg.progress) {
                setUpdateProgress(msg.progress);
                setUpdateStatusText(t`Downloading videos...`);
            } else if(msg.complete) {
                setUpdateProgress(1);
                setUpdateStatusText(t`Video download complete!`);
                queryClient.invalidateQueries({ queryKey: ["ceremony-videos"] })
            } else if(msg.error) {
                setUpdateProgress(1);
                setUpdateStatusText(t`Video download failed: ` + msg.error);
            }
            if(msg.complete || msg.error) {
                ws.close();
            }
        };
    }

    return <div>
        <Button className={"mr-2"} variant={"success"} onClick={() => updateVideos()}>{t`Download/Update Videos`}</Button>
        {updateStatusText ? <div>
            <div>{updateStatusText}</div>
            {updateProgress != undefined ? <ProgressBar now={updateProgress} max={1}></ProgressBar> : null}
        </div> : null}
    </div>
}

type VideoManifest = {
    key: string,
    name: string,
    path: string,
    subtitleLocales: {
        locale: string,
        path: string,
    }[]
}[]

function VideoPlayback({eventCode}: {
    eventCode: string
}) {
    const videoQuery = useQuery<VideoManifest>({
        queryKey: ["ceremony-videos"],
        queryFn: async function() {
            const res = await fetch(`/ceremony-videos/manifest.json`);
            if(res.status == 404) {
                return []
            } else if (!res.ok) {
                throw new Error(`Error fetching video manifest: ${res.statusText}`);
            } else {
                return await res.json();
            }
        }
    })

    const [selectedVideo, setSelectedVideo] = useState<string | null>(null);
    const [subtitleLocale, setSubtitleLocale] = useState<string>('en');
    const [customSubtitles, setCustomSubtitles] = useState<Record<string, FileData>>({});

    const videoData = videoQuery.data?.find(d => d.key == selectedVideo);

    return <fieldset>
        <legend>{t`Videos`}</legend>
        <Alert variant={"warning"}>
            {t`Must be online to download videos.`}<br/>
            {t`Video will play on all audience displays.`}<br/>
            {t`Audio will not necessarily be synced between displays, so ensure you are only playing audio from one display.`}<br/>
            {t`Videos are not necessarily chroma-key safe. Ensure you are displaying the scoring display without chroma keying (transparent overlay is ok) when playing videos or play videos through an external system.`}
        </Alert>
        {videoQuery.data && videoQuery.data.length > 0 ? <Form.Control as="select" custom style={{width: 'auto'}} className={"mb-2"} value={selectedVideo || undefined} onChange={(e) => setSelectedVideo(e.target.value)}>
            <option value="">{t`Select a video`}</option>
            {videoQuery.data.map((v) => <option key={v.key} value={v.key}>{v.name}</option>)}
        </Form.Control> : (videoQuery.data ? <span className={"mr-2"}>{t`Videos must be downloaded`}</span> : null)}
        <Form.Group className={"mb-2"}>
            <Form.Label>{t`Subtitles`}</Form.Label>
            <Form.Control as="select" custom style={{width: 'auto'}} className={"ml-2"} value={subtitleLocale} onChange={(e) => setSubtitleLocale(e.target.value)} disabled={!selectedVideo}>
                {videoData?.subtitleLocales.map((v) => <option key={v.locale} value={v.locale}>{new Intl.DisplayNames(document.documentElement.lang, {
                    type: 'language'
                }).of(v.locale)}</option>) || <option>{t`Pick a video first`}</option>}
                <option value={"zz"}>{t`Custom`}</option>
            </Form.Control>
            {subtitleLocale == "zz" && selectedVideo ? <Button variant={!customSubtitles[selectedVideo] ? "warning" : "secondary"} className={"ml-2"} onClick={() => fileUploadDialog({
                label: t`Upload Subtitle File`,
                text: t`Upload a subtitle file in WebVTT format (.vtt)`,
                onComplete: (file?: FileData) => {
                    if(file) {
                        setCustomSubtitles(was => ({...was, [selectedVideo]: file}));
                    }
                },
                filter: {
                    regex: 'text/vtt',
                    error: t`File must be a .vtt subtitle file`
                }
            })}>{customSubtitles[selectedVideo] ? 'Replace' : 'Upload'}</Button> : null}
        </Form.Group>
        <Button className={"mr-2 mb-2"} variant={"success"} onClick={() => playVideo(eventCode, videoData!.path, subtitleLocale == 'zz' ? customSubtitles[selectedVideo!].previewUrl : videoData!.subtitleLocales.find(s => s.locale == subtitleLocale)?.path || '')} disabled={!selectedVideo || (subtitleLocale == 'zz' && !customSubtitles[selectedVideo])}>{t`Play Video`}</Button>
        <Button className={"mr-2 mb-2"} variant={"success"} onClick={() => stopVideo(eventCode)} disabled={!selectedVideo}>{t`Abort Video`}</Button>
        <VideoUpdater />
    </fieldset>
}

export default function VideoSwitch({eventCode, displayData, fieldCount, showMeetRankings, pinField, isDualDivisionParent, isDivision, isRoundRobin, divisions}: {
    eventCode: string,
    displayData: DisplayDataWithConfig[],
    fieldCount: number,
    showMeetRankings: boolean,
    pinField?: number,
    isDualDivisionParent: boolean,
    isDivision: boolean,
    isRoundRobin: boolean,
    divisions: string[]
}) {
    const [message, setMessage] = useState('');
    const [hasMessage, setHasMessage] = useState(false);
    const [advancedEditor, setAdvancedEditor] = useState(false);
    // We need this slightly awkward logic to handle the fact that the RCE may end up with empty p/br tags and nothing else
    useEffect(() => {
        const el = document.createElement("div");
        el.innerHTML = message;
        let hasMessage = false;
        hasMessage ||= el.textContent ? el.textContent.length > 0 : false;
        hasMessage ||= el.getElementsByTagName("img").length > 0;
        hasMessage ||= el.getElementsByTagName("video").length > 0;
        hasMessage ||= el.getElementsByTagName("iframe").length > 0;
        setHasMessage(hasMessage);
        return () => el.remove();
    }, [message])

    return <div>
        <fieldset>
            <legend>{t`General Information`}</legend>
            <Button className={"mr-2"} variant={"success"} onClick={() => showSlideshow(eventCode, pinField)}>{t`Show Slideshow`}</Button>
            <Button className={"mr-2"} variant={"success"} onClick={() => showSponsors(eventCode, pinField)}>{t`Show Sponsors`}</Button>
            <Button className={"mr-2"} variant={"success"} onClick={() => showWifi(eventCode, pinField)}>{t`Show Wifi Reminder`}</Button>
            <Button className={"mr-2"} variant={"success"} onClick={() => showAudienceKey(eventCode, pinField)}>{t`Show Audience Key`}</Button>
            <Button className={"mr-2"} variant={"success"} onClick={() => showSafetySecurity(eventCode, pinField)}>{t`Show Safety & Security`}</Button>
        </fieldset>
        <fieldset>
            <legend>{t`Playoff`}</legend>
            {/* TODO clean up conditional logic here depending on if we revive any form of giant bracket (e.g. for worlds) or not */}
            { (isDualDivisionParent || isDivision) ? <Button className={"mr-2"} variant={"success"} onClick={() => showBracket(eventCode, BracketStyle.TWO_LEVEL, pinField)}>{isDivision ? t`Show Bracket (this division)` : (isRoundRobin ? t`Show Playoff Rankings` : t`Show Bracket (interdivisional only)`)}</Button> : null }
            {(isDualDivisionParent || isDivision) ? null : <Button className={"mr-2"} variant={"success"} onClick={() => showBracket(eventCode, BracketStyle.FULL, pinField)}>{(isDualDivisionParent || isDivision) ? t`Show Bracket (full)` : t`Show Bracket`}</Button>}
            <Button className={"mr-2"} variant={"success"} onClick={() => showAllianceSelection(eventCode, pinField)} disabled={!!pinField}>{t`Show Alliance Selection`}</Button>
        </fieldset>
        <fieldset>
            <legend>{t`Other Displays`}</legend>
            <Button className={"mr-2"} variant={"success"} onClick={() => showRanks(eventCode, pinField)} disabled={isRoundRobin} title={isRoundRobin ? t`Playoff rankings can be found above` : undefined}>{t`Show Ranks & Results`}</Button>
            <Button className={"mr-2"} variant={"success"} onClick={() => showBlank(eventCode, pinField)}>{t`Show Blank Screen`}</Button>
            <Button className={"mr-2"} variant={"success"} onClick={() => showVideo(eventCode, pinField)}>{t`Show Video Only (Overlay)`}</Button>
            <Button className={"mr-2"} variant={"success"} onClick={() => showOnlineResults(eventCode, pinField)}>{t`Show Online Results Info`}</Button>
            <Button className={"mr-2"} variant={"success"} onClick={() => showInspectionStatus(eventCode, pinField)}>{t`Show Inspection Status`}</Button>
        </fieldset>
        <fieldset>
            <legend>{t`Message`}</legend>
            {advancedEditor ? <textarea className={"messageEditor"} onChange={(e) => setMessage((e.target as HTMLTextAreaElement).value)}>
                {message}
            </textarea> : <ReactQuill className="bg-white text-dark messageEditor" theme="snow" value={message}
                        modules={{toolbar: [
                                [{ 'color': [] }, 'italic', 'underline', 'strike'],
                                [{'list': 'ordered'}, {'list': 'bullet'}],
                                ['image'],
                                ['clean']
                            ]}}
                        onChange={(content) => {
                            setMessage(content);
                        }} />}
            <Button className={"btn-xs my-1"} variant={"light"} onClick={() => setAdvancedEditor((old) => !old)}>
                {advancedEditor ? t`Basic Editor` : t`Raw HTML`}
            </Button><br/>
            <Button className={"mr-2"} variant={"success"} disabled={!hasMessage} onClick={() => showMessage(eventCode, message, pinField)}>{t`Show Message`}</Button>
        </fieldset>
        <VideoPlayback eventCode={eventCode} />
        <fieldset>
            <legend>{t`Connected Displays`}</legend>
            <DisplaysTable eventCode={eventCode} displayData={displayData} fieldCount={fieldCount} showMeetRankings={showMeetRankings} isDualDivisionParent={isDualDivisionParent} divisions={divisions} />
        </fieldset>
    </div>
}
