import {useCallback, useState} from "react";
import {Tab} from "react-bootstrap";

import {useTimer} from "ftc-common/hooks"
import {confirmDialog, messageDialog, promptDialog} from "first-common/dialogs";

import "./MatchControl.css";
import VideoSwitch from "./VideoSwitch";
import Settings from "./Settings";
import Schedule from "./Schedule";
import CurrentMatches from "./CurrentMatches";
import ActionButtons from "./ActionButtons";
import ScoreEdit from "./ScoreEdit";
import {batchPost, lockoutMatch, postMatch} from "./api/match";
import AllianceSelection from "./AllianceSelection";
import SupportChat from "../chat/SupportChat";
import {resetSelection} from "./api/allianceSelection";
import ButtonTabs from "./ButtonTabs";
import DeauthNotifications from "./DeauthNotifications";
import DeauthDetails from "./DeauthDetails";
import {abortMatch, commitMatch, previewMatch, randomizeMatch, showMatch, showRandom, startMatch, useControlConnection} from "./connection";
import {t} from "ftc-common/i18n";
import {EventKey} from "react-bootstrap/esm/types";
import {AllianceLastMatchTimeout, LastOnFieldTimeout, MatchInfo, MatchTeam, PlayoffType, ScheduledStartTimeout, T206Timeout, TimeoutReference, TimeoutType} from "ftc-common/javaTypes";
import {isT206DependencyTimeout} from "ftc-common/timeoutUtils";
import {getExpectedStartTimer} from "ftc-common/displays/util";
import PresentAwards from "ftc-common/awards/manage/PresentAwards";
import {ParsedMatchTiming} from "ftc-common/utils";
import {MatchType} from "../javaTypes";
import {delayStr} from "../util";

async function resetElims(eventCode: string) {
    if(!await confirmDialog({
        label: t`Reset Alliance Selection?`,
        text: t`This will delete all generated elimination matches and undo all of alliance selections. This action cannot be undone.`,
        buttonText: t`Reset Alliances`
    })) {
        return;
    }
    // TODO does this need to display any special error messages?
    if(!await resetSelection(eventCode)) {
        messageDialog({
            label: t`Failed to Reset Alliances`,
            text: t`Unable to reset alliances`
        })
    }
}

function isApplicableTimeout(nextMatch: MatchInfo<MatchTeam>, timeout: TimeoutReference) {
    switch (timeout.type) {
        case TimeoutType.G301: return false;
        case TimeoutType.RUNNING_MATCH: return false;
        case TimeoutType.SCHEDULED_START: return (timeout as ScheduledStartTimeout).match === nextMatch?.number;
        case TimeoutType.T206: return (timeout as T206Timeout).targetMatch === nextMatch.number;
        case TimeoutType.LAST_ON_FIELD: return (timeout as LastOnFieldTimeout).field === nextMatch.field;
        case TimeoutType.ALLIANCE_LAST: return [nextMatch.red.seed, nextMatch.blue.seed].includes((timeout as AllianceLastMatchTimeout).alliance);
        case TimeoutType.T206_MATCH_DEPENDENCY: return true;
    }
}

const initialTab = window.location.hash.replace("#", "") || 'schedule';

export default function MatchControl({eventCode, isMeet, fieldCount, pinField, isDualDivisionParent, divisions, isDivision, timing}: {
    eventCode: string, isMeet: boolean, fieldCount: number, pinField: number, isDualDivisionParent: boolean, divisions: string[], isDivision: boolean, timing: ParsedMatchTiming
}) {
    const [deauthDetailsVisible, setDeauthDetailsVisible] = useState(false);
    const [tab, setTab] = useState(initialTab);
    const [unreadMessages, setUnreadMessages] = useState(0);
    const [editingMatchNum, setEditingMatchNum] = useState(initialTab.startsWith("edit") ? parseInt(initialTab.split("-")[1]) : -1);
    const {
        nowCallback,
        isConnected,
        matchData,
        displayUpdates,
        deauthEvents,
        settings,
        qualsActive,
        practiceActive,
        playoffType,
        selectionState,
        timeoutData,
        isArchived,
        syncStatus,
        displayData,
        loadedMatch,
        activeMatch,
        remaining,
        loadMatch,
        nextMatchNum
    } = useControlConnection(eventCode, timing, pinField, () => {
        setEditingMatchNum(-1)
        goToTab("schedule")
    });

    function goToTab(tab: EventKey | null) {
        window.location.hash = tab as string;
        setTab(tab as string);
    }

    // Derived state
    const matches = matchData.matches;
    const activeType = matchData.activeType;
    const unsavedMatches = matches.filter(m => m.state === 'SUBMITTED' || m.state === 'REVIEW');
    const editingMatch = matches.find(m => m.number === editingMatchNum);


    async function editMatch(num: number) {
        setEditingMatchNum(num)
        if(num > 0) {
            goToTab(`edit-${num}`)
        } else {
            goToTab("schedule")
        }
    }

    const enrichedCommitMatch = useCallback(async (num: number, verifyCommit: boolean = false) => {
        const match = matches.find(m => m.number === num)
        if(match?.seriesDescription?.matchesToWin == 0) {
            if(!await confirmDialog({
                label: t`Commit Round Robin Standalone`,
                text: t`This is a round robin match! Are you sure you want to commit this match on its own?`,
                buttonText: t`Commit`
            })) {
                return
            }
        }
        await commitMatch(eventCode, num, matches, false, verifyCommit)
    }, [matches])

    const enrichedPostMatch = useCallback(async (num: number) => {
        const match = matches.find(m => m.number === num)
        if(match?.seriesDescription?.matchesToWin == 0) {
            if(!await confirmDialog({
                label: t`Post Round Robin Standalone`,
                text: t`This is a round robin match! Are you sure you want to post this match on its own?`,
                buttonText: t`Post`
            })) {
                return
            }
        }
        if(!await postMatch(eventCode, num)) {
            messageDialog({
                label: t`Failed to Post Match`,
                text: t`Match post failed.  Please refresh and try again.`
            })
        }
    }, [matches])

    const scheduleArgs = {
        liveScoring: settings.liveScoring,
        archived: isArchived,
        loadMatch,
        eventCode,
        fieldCount,
        editMatch,
        commitMatch: enrichedCommitMatch,
        postMatch: enrichedPostMatch,
        batchPost: async (num: number) => {
            if(!await batchPost(eventCode, num)) {
                messageDialog({
                    label: t`Failed to Post Batch`,
                    text: t`Batch post failed.  Please refresh and try again.`
                })
            }
        },
        replayMatch: async (num: number) => {
            const match = matches.find(m => m.number === num)
            const matchName = match!.name
            if(!await confirmDialog({
                label: t`Replay ${matchName}?`,
                text: t`This will overwrite any saved scores and data for ${matchName}!`,
                buttonText: t`Replay Match`
            })) {
                return;
            }
            await loadMatch(num)
        },
        qualsActive,
        practiceActive
    }

    const lastRunMatch = [...matches].sort((m1, m2) => m2.start - m1.start)[0];

    const assumedNextMatch = timeoutData.assumedNext?.filter(x => !!x)[0];
    const expectedTimeout = assumedNextMatch && timeoutData.activeTimeouts ? getExpectedStartTimer(assumedNextMatch, timeoutData.activeTimeouts, isApplicableTimeout, nowCallback) : timeoutData.activeTimeouts?.find(isT206DependencyTimeout)
    const timeoutTimer = useTimer({
        startAt: expectedTimeout?.timeoutStart,
        duration:  (expectedTimeout?.timeoutDuration ?? 0) / 1000,
        nowCallback
    });

    const headerRow = <div className={"d-flex justify-content-center"}>
        <h1>{t`Match Control`} <span className={"badge badge-primary"}>{pinField ? t`Field ${pinField}` : ''}</span> {activeType === 'TEST' ? t`- TEST MODE` : ''} {activeType === 'PRACTICE' ? t`- Practice Matches` : ''}</h1>
    </div>

    const activeMatchRunning = !!(activeMatch && activeMatch?.state !== 'REVIEW' && activeMatch?.state !== 'SUBMITTED');

    return <>
        <div className={`controlHeading ${activeType === 'TEST' || activeType === 'PRACTICE' ? 'test' : ''}`}>
            {headerRow}
            {isConnected ? null : <div className={"alert alert-warning text-center h6 fixed-top w-25 mx-auto"}>{t`DISCONNECTED!!`}</div>}
            <CurrentMatches loadedMatch={loadedMatch} activeMatch={activeMatch} matchRemaining={remaining} timeoutTimer={timeoutTimer} timeout={expectedTimeout} settings={settings} timing={timing} />
            {settings.hrControl && settings.hrControl !== 'NONE' ? <div className={"alert alert-danger text-center"} style={{margin: '1ch'}}>External control of some elements of Match Control enabled!</div> : null}
            <ActionButtons loadedMatch={loadedMatch} activeMatch={activeMatch} editingMatch={editingMatch} matches={matches}
                           previewMatch={(number, forceFullscreen) => previewMatch(eventCode, number, forceFullscreen)}
                           randomizeMatch={(number, opts) => randomizeMatch(eventCode, number, opts)}
                           showRandom={(number) => showRandom(eventCode, number)}
                           showMatch={(number) => showMatch(eventCode, number)}
                           startMatch={(number) => startMatch(eventCode, number)}
                           abortMatch={(number, isDiscard) => abortMatch(eventCode, number, isDiscard)}
                           commitAndPostMatch={(number) => commitMatch(eventCode, number, matches, true)}
                           commitMatch={(number) => commitMatch(eventCode, number, matches)}
                           batchPost={(round) => batchPost(eventCode, round)}
                           hasNextMatch={nextMatchNum > 0}
                           loadNextMatch={() => loadMatch(nextMatchNum)}
                           displayUpdates={Object.values(displayUpdates)}
                           showSeparatePreviews={matches.length > 0 && matches[0].type === 'ELIMS' && displayData.some(d => d.data.overlay) && (playoffType == PlayoffType.DOUBLE_ELIMINATION || playoffType == PlayoffType.DOUBLE_ELIMINATION_WITH_FINALS)}
                           settings={settings} isArchived={isArchived} warnIfNotPost={false} controlSettings={'FULL'}/>
        </div>

        <ButtonTabs
            activeKey={tab}
            onSelect={goToTab}
            className="controlTabs"
        >
            <Tab eventKey="schedule" title={t`Schedule`}>
                <Schedule matches={matches} {...scheduleArgs} testMode={activeType === 'TEST'} activeMatchRunning={activeMatchRunning}/>
            </Tab>
            <Tab eventKey="incomplete" title={<span>{t`Incomplete Matches`} {unsavedMatches.length > 0 ? <span className={"tabBadge badge badge-danger"}>{unsavedMatches.length}</span> : null}</span>}>
                <Schedule matches={unsavedMatches} {...scheduleArgs} activeMatchRunning={activeMatchRunning} />
            </Tab>
            <Tab eventKey={`edit-${editingMatchNum}`} title={t`Score Edit`} disabled={!editingMatch}>
                <ScoreEdit settings={settings} match={editingMatch} eventCode={eventCode} isArchived={isArchived} closeMatch={() => editMatch(-1)}
                           showHelp={() => goToTab("help")}
                           lockoutMatch={(number: number) => lockoutMatch(eventCode, number)}
                           commitMatch={enrichedCommitMatch}
                           postMatch={(number: number) => enrichedPostMatch(number)}
                           activeMatchRunning={activeMatchRunning}
                />
            </Tab>
            <Tab eventKey="active" title={t`Active Match`} disabled={!settings.liveScoring}>
                <ScoreEdit active eventCode={eventCode} settings={settings} match={activeMatch} openMatchForEditing={editMatch}/>
            </Tab>
            <Tab eventKey="settings" title={t`Settings`} disabled={pinField > 0}>
                <Settings eventCode={eventCode} settings={settings} selectionState={selectionState}
                          isMeet={isMeet} activeMatch={activeMatch} activeType={activeType} timeoutData={timeoutData}
                          resetElims={() => resetElims(eventCode)}
                          syncStatus={syncStatus} nowCallback={nowCallback} isArchived={isArchived}
                          showDeauthDetails={Object.keys(deauthEvents).length > 0 ? () => setDeauthDetailsVisible(true) : undefined} showHelp={() => goToTab("help")}
                          isDualDivisionParent={isDualDivisionParent} matches={matches} unsavedMatchCount={unsavedMatches.length} />
            </Tab>
            <Tab eventKey="alliance" title={t`Alliance Selection`} disabled={activeType === 'TEST' || activeType == 'PRACTICE' || (activeType == 'ELIMS' && !settings.allowBackupsOverride) || isArchived || pinField > 0 || isDualDivisionParent}>
                <AllianceSelection eventCode={eventCode} matches={matches} selectionState={selectionState} activeType={activeType} settings={settings} />
            </Tab>
            <Tab eventKey="video" title={t`Video Switch`}>
                <VideoSwitch eventCode={eventCode} displayData={displayData} fieldCount={fieldCount} pinField={pinField} showMeetRankings={!!settings.showMeetRankings}
                             isDualDivisionParent={isDualDivisionParent} isDivision={isDivision} isRoundRobin={matches.some(m => m.seriesDescription?.matchesToWin === 0)} divisions={divisions}/>
            </Tab>
            <Tab eventKey="awards" title={t`Present Awards`}>
                <div className={"p-3"}>
                    <PresentAwards queryInterval={!isArchived && activeType === MatchType.ELIMS ? 30 * 1000 : undefined}/>
                </div>
            </Tab>
            <Tab eventKey="help" title={<span>{t`Help`} {unreadMessages > 0 ? <span className={"tabBadge badge badge-warning"}>{unreadMessages}</span> : null}</span>} >
                <div ref={(el) => el && el.appendChild(document.getElementById("feedbackContent")!)} />
                <SupportChat setUnreadMessages={setUnreadMessages}/>
            </Tab>
        </ButtonTabs>

        <div className="footer">
            <div className={`syncStatusLight ${syncStatus.status}`}
                 title={syncStatus.description + (syncStatus.lastSyncTime > 0 ? "\r\nLast Success: " + new Date(syncStatus.lastSyncTime).toLocaleTimeString() : "")}></div>
            <span title={delayStr(lastRunMatch?.scheduledStart, lastRunMatch?.start)}>{playoffType === PlayoffType.ROUND_ROBIN_WITH_FINALS ? "da Vinci is never late, nor early " : delayStr(lastRunMatch?.scheduledStart, lastRunMatch?.start)}</span>
        </div>

        <DeauthNotifications deauthEvents={deauthEvents} showDeauthDetails={() => setDeauthDetailsVisible(true)} />
        {deauthDetailsVisible ? <DeauthDetails deauthEvents={deauthEvents} hide={() => setDeauthDetailsVisible(false)}/> : null}
    </>
}
