import './Schedule.css'
import { t } from 'ftc-common/i18n';
import {Button} from "react-bootstrap";
import {TestMatchDialog} from "./LoadMatchDialog";
import {useState} from "react";
import { ControlMatch } from './connection';
import {AllianceDescription, SeriesAllianceDescription} from "ftc-common/javaTypes";

const buttonAttrs = {
    className: 'mr-2',
    variant: 'light'
}

// @ts-expect-error xs is not an official size
const ButtonXs = (props: Omit<ButtonProps, 'size'>) => <Button size={"xs"} {...props}/>

export function isSeriesAllianceDescription(description: AllianceDescription): description is SeriesAllianceDescription {
    return 'series' in description;
}

export default function Schedule({matches, liveScoring, archived, loadMatch, editMatch, commitMatch, postMatch, batchPost, replayMatch,
    testMode, eventCode, fieldCount, qualsActive, practiceActive, activeMatchRunning}: {
    matches: ControlMatch<any, any>[],
    liveScoring?: boolean,
    archived: boolean,
    loadMatch: (matchNumber: number) => void,
    editMatch: (matchNumber: number) => void,
    commitMatch: (matchNumber: number) => void,
    postMatch: (matchNumber: number) => void,
    batchPost: (series: number) => void,
    replayMatch: (matchNumber: number) => void,
    testMode?: boolean,
    eventCode: string,
    fieldCount: number,
    qualsActive?: boolean,
    practiceActive?: boolean,
    activeMatchRunning: boolean
}) {
    const [testMatchCreateVisible, setTestMatchCreateVisible] = useState(false);
    if(matches.length > 0 && matches[0].type === 'QUALS' && !qualsActive) {
        return <div className={"testFooter"}>
            {t`Qualification schedule is not active.`}<br/>
            <a target='_blank' href='../dashboard/schedule/quals/'>{t`Activate it here.`}</a>
        </div>
    }
    if(matches.length > 0 && matches[0].type === 'PRACTICE' && !practiceActive) {
        return <div className={"testFooter"}>
            {t`Practice schedule is not active.`}<br/>
            <a target='_blank' href='../dashboard/schedule/practice/'>{t`Activate it here.`}</a>
        </div>
    }
    const hide3 = !matches.some(m => m.blue.team3Display || m.red.team3Display);
    const hasRounds = matches.some(m => m.seriesDescription?.round)
    return <>
        <table className={"schedule"}>
            <thead>
                <tr>
                    <th>Match</th>
                    {hasRounds ? <th>Round</th> : null}
                    <th>Field</th>
                    <th>State</th>
                    <th>Red Score</th>
                    {hasRounds ? <th>Red</th> : null}
                    <th>Red 1</th>
                    <th>Red 2</th>
                    <th hidden={hide3}>Red 3</th>
                    <th>Blue 1</th>
                    <th>Blue 2</th>
                    <th hidden={hide3}>Blue 3</th>
                    {hasRounds ? <th>Blue</th> : null}
                    <th>Blue Score</th>
                    <th/>
                    <th/>
                    <th/>
                    <th/>
                    <th/>
                </tr>
            </thead>
            <tbody>
            {matches?.map(m => {
                const editable = m.type !== 'ELIMS' || !matches.filter(m2 => m2.state == 'COMMITTED').some(m2 => m2.seriesDescription &&
                    ((isSeriesAllianceDescription(m2.seriesDescription.red) && m2.seriesDescription.red.series == m.seriesDescription?.series) ||
                        (isSeriesAllianceDescription(m2.seriesDescription.blue) && m2.seriesDescription.blue.series == m.seriesDescription?.series)) ||
                        // If there exists a later match is in the same series that is committed and only happened because of the outcome of this (and other) matches
                        // then this match should not be editable
                        (m.seriesDescription && m.seriesDescription.series == m2.seriesDescription?.series && m2.number > m.number && m2.number > m.seriesDescription.matchesToWin) ||
                        (m2.seriesDescription?.isFinals && !m.seriesDescription?.isFinals));
                const aName = (a?: string) => {
                    if (!a || a.length === 0) return "";
                    return (a.charAt(0) >= '0' && a.charAt(0) <= '9') ? "A" + a : a;
                }
                const wholeRound = matches.filter(m2 => m2.seriesDescription?.round === m.seriesDescription?.round);
                const isFirstOfRound = m.seriesDescription?.round && !wholeRound.some(m2 => m2.number < m.number);
                const isLastOfRound = m.seriesDescription?.round && !wholeRound.some(m2 => m2.number > m.number);
                const isRoundRobin = m.seriesDescription?.matchesToWin == 0
                return <tr key={m.number} className={isRoundRobin && isLastOfRound ? "scheduleBottomBorder" : (isRoundRobin && isFirstOfRound ? "scheduleTopBorder" : "")}>
                    <td>{m.name}</td>
                    {hasRounds ? <td>{m.seriesDescription?.round}</td> : null}
                    <td>{m.field}</td>
                    <td>{m.state}</td>
                    <td>{Math.max(0, m.redTotal || 0)}</td>
                    {hasRounds ? <td>{aName(m.redSeed)}</td> : null}
                    <td>{m.red.team1Display}</td>
                    <td>{m.red.team2Display}</td>
                    <td hidden={hide3}>{m.red.team3Display}</td>
                    <td>{m.blue.team1Display}</td>
                    <td>{m.blue.team2Display}</td>
                    <td hidden={hide3}>{m.blue.team3Display}</td>
                    {hasRounds ? <td>{aName(m.blueSeed)}</td> : null}
                    <td>{Math.max(0, m.blueTotal || 0)}</td>
                    {editable && (m.state === "UNPLAYED" || m.state === "RANDOMIZED") && m.number > 0 ? <>
                        <td><ButtonXs id={"qualificationPlayButton"+m.number} {...buttonAttrs} onClick={() => loadMatch(m.number)} disabled={archived}>{t`Play`}</ButtonXs></td>
                        <td><ButtonXs id={"qualificationEnterScoresButton"+m.number} {...buttonAttrs} onClick={() => editMatch(m.number)} disabled={archived}>{t`Enter Scores`}</ButtonXs></td>
                    </>: null }
                    {m.state === "COMMITTED" || m.state === "SUBMITTED" ? <td>{editable ? <ButtonXs {...buttonAttrs} onClick={() => replayMatch(m.number)} disabled={archived}>{t`Replay`}</ButtonXs> : ""}</td> : null }
                    {m.state === 'SUBMITTED' && liveScoring ? <td><ButtonXs {...buttonAttrs} onClick={() => commitMatch(m.number)}>{t`Commit`}</ButtonXs></td> : null }
                    {m.state === 'COMMITTED' ? <td><ButtonXs {...buttonAttrs} onClick={() => postMatch(m.number)} disabled={activeMatchRunning}>{t`Post`}</ButtonXs></td> : null }
                    {editable && (m.state === 'COMMITTED' || m.state === "SUBMITTED") ? <td><ButtonXs {...buttonAttrs} onClick={() => editMatch(m.number)}>{liveScoring || m.state === "COMMITTED" ? t`Edit` : t`Enter Scores`}</ButtonXs></td> : null }
                    {m.state === 'REVIEW' ? <td><ButtonXs {...buttonAttrs} onClick={() => editMatch(m.number)}>{t`View`}</ButtonXs></td> : null }
                    {isRoundRobin && isFirstOfRound && wholeRound.every(m => m.state == 'COMMITTED') ? <td rowSpan={wholeRound.length}><Button size={"sm"} {...buttonAttrs} onClick={() => batchPost(m.seriesDescription!.round)} disabled={activeMatchRunning}>{t`Post Round`}</Button></td> : null}
                    {/* This spans up to 4 columns, depending on how many columns there actually are */}
                    <td colSpan={5}/>
                </tr>
            })}
            </tbody>
        </table>
        {testMode ? <>
            <div className={"testFooter"}>
                {t`System in Test Mode. Click to create a new Test Match:`} <Button variant={"success"} onClick={() => setTestMatchCreateVisible(true)}>{t`Add Test Match`}</Button><br/>
                {t`Use the Settings tab to exit Test Mode.`}
            </div>
            <TestMatchDialog eventCode={eventCode} close={() => setTestMatchCreateVisible(false)} visible={testMatchCreateVisible} fieldCount={fieldCount} />
        </>: null}
    </>
}