import { Nav, TabContainer, TabContent, TabPane, TabsProps } from "react-bootstrap";
import ErrorBoundary from "../LocalErrorBoundary";
import { map } from "react-bootstrap/ElementChildren";
import { ReactElement } from "react";

function renderTab(child: ReactElement) {
    const { title, eventKey, disabled, tabClassName, id } = child.props;
    if (title == null) {
        return null;
    }

    return (
        <Nav.Item>
            <Nav.Link as={"button"}
                eventKey={eventKey}
                disabled={disabled}
                id={id}
                className={tabClassName}>{title}</Nav.Link>
        </Nav.Item>
    );
}

// adapted from https://github.com/react-bootstrap/react-bootstrap/blob/bs4-dev/src/Tabs.tsx
export default function ButtonTabs({ children, activeKey, onSelect, ...navProps }: TabsProps & { className?: string }) {
    return <TabContainer
        activeKey={activeKey}
        onSelect={onSelect}
    >
        <Nav {...navProps} variant="tabs" role="tablist" as="nav">
            {map(children, renderTab)}
        </Nav>

        <TabContent>
            {map(children, child => {
                const childProps = { ...child.props };

                delete childProps.title;
                delete childProps.disabled;
                delete childProps.tabClassName;

                const children = childProps.children;
                delete childProps.children;

                return <TabPane {...childProps} >
                    <ErrorBoundary>
                        {children}
                    </ErrorBoundary>
                </TabPane>;
            })}
        </TabContent>
    </TabContainer>
}