export async function setConfig(eventCode: string, key: string, value: any) {
    await fetch(`/event/${eventCode}/config/set/`, {
        method: "POST",
        body: new URLSearchParams({ key, value })
    })
}

export async function setTestMode(eventCode: string, state: boolean) {
    await fetch(`/event/${eventCode}/control/testmode/${state}/`, {
        method: "POST",
    })
}

export async function advanceToQuals(eventCode: string) {
    await fetch(`/event/${eventCode}/control/quals/`, {
        method: "POST",
    })
}

export async function returnToPractice(eventCode: string) {
    await fetch(`/event/${eventCode}/control/practice/`, {
        method: "POST",
    })
}

export async function testSync(eventCode: string) {
    const res = await fetch(`/event/${eventCode}/control/sync/test/`, {
        method: "POST",
    })
    return await res.text();
}

export async function syncNow(eventCode: string) {
    const res = await fetch(`/event/${eventCode}/control/sync/now/`, {
        method: "POST",
    })
    return await res.text();
}

export async function downloadVideos() {
    const res = await fetch(`/manage/video_download/`, {
        method: "POST",
    })
    return res.ok;
}

