export type ScoreType = DecodeScores
export type ScoreDetailType = DecodeScoresDetail
type ScoreTypeSetValue = <K extends keyof ScoreType>(key: K, value: ScoreType[K]) => void
type ParallelScoreTypeSetValue = <K extends keyof ScoreType>(key: K, value: ScoreType[K], otherValue: ScoreType[K]) => void

interface Robots {
    robot1: number | null,
    robot2: number | null
}

interface RobotData {
    teams: (number | undefined)[],
    noshows: (number | undefined)[]
}

interface RobotNumbers {
    robot1: number,
    robot2: number,
    ns1: boolean,
    ns2: boolean
}

function toRobotData(teams: (number | undefined)[], details?: ScoreType): RobotData {
    return {teams: teams, noshows: ([1, 2, 3] as const).map(x => details?.[`noshow${x}`])}
}

function replaceClassifierState(state: ArtifactType, position: number, existing: ArtifactType[]): ArtifactType[] {
    const newState = [...existing];
    if (position < 0 || position >= newState.length) {
        throw new Error(`Invalid position ${position} for classifier state`);
    }
    newState[position] = state;
    return newState;
}

