function robotNoshowCombos(robots: RobotData): RobotNumbers {
    if (robots?.teams[2]) { // 3-teams
        let robot1 = 0, robot2 = 0;
        if (!robots.noshows.some(x => x && x > 0)) { // not selected yet! doesnt matter.
            return {robot1: robots.teams[0] || 0, robot2: robots.teams[1] || 0, ns1: false, ns2: false};
        }
        if (!robots.noshows[0]) {
            robot1 = robots.teams[0] || 0;
        }
        if (!robots.noshows[1]) {
            if (!robot1) {
                robot1 = robots.teams[1] || 0;
            } else {
                robot2 = robots.teams[1] || 0;
            }
        }
        if (!robots.noshows[2]) {
            if (!robot1) {
                robot1 = robots.teams[2];
            } else {
                robot2 = robots.teams[2];
            }
        }
        return {robot1: robot1, robot2: robot2, ns1: !robot1, ns2: !robot2};
    } else {
        return {
            robot1: robots?.teams[0] || 0,
            robot2: robots?.teams[1] || 0,
            ns1: !!(robots?.noshows[0] || !robots?.teams[0]),
            ns2: !!(robots?.noshows[1] || !robots?.teams[1])
        };
    }
}

