export function Randomization({random}: {
    random?: number
}) {
    const randomizationText = random && random > 0 ? (["", "MOTIF 1 (ID 21)", "MOTIF 2 (ID 22)", "MOTIF 3 (ID 23)"])[random] : "";
    const gateSvg = useAsset('img/decode/gate.svg');

    return <div className={"randomization"}>
        <div className="text-center">{randomizationText ? t`Randomization: ${randomizationText}` : 'MATCH NOT RANDOMIZED!'}</div>
        <div className="text-center hr-artifacts">
            <ReactSVG src={gateSvg} className={"randomizer-icon"}></ReactSVG>
            <Artifact value={randomizationText && random ? randomizationArtifacts[random][0] : ArtifactType.NONE} />
            <Artifact value={randomizationText && random ? randomizationArtifacts[random][1] : ArtifactType.NONE} />
            <Artifact value={randomizationText && random ? randomizationArtifacts[random][2] : ArtifactType.NONE} />
            <ReactSVG src={faSquare} className={"randomizer-icon"}></ReactSVG>
        </div>
    </div>
}