import {Button, Modal} from "react-bootstrap";
import {useEffect, useState} from "react";

import './MatchHistoryDialog.css'
import {getMatchHistory, restoreMatchHistory} from "./api/match";
import { ControlMatch } from "./connection";
import { t } from "ftc-common/i18n";

export default function MatchHistoryDialog({visible, close, eventCode, match, updateMatchDetails}: {
    visible: boolean, close: () => void, eventCode: string, match?: ControlMatch<any, any>, updateMatchDetails: (details: any) => void
}) {
    const [commits, setCommits] = useState<string[]>([])
    const [selectedRecord, setSelectedRecord] = useState(-1);
    const [sheetData, setSheetData] = useState<{__html: string}>();

    useEffect(() => {
        (async () => {
            if(!visible || !match) {
                setSelectedRecord(-1);
                return;
            }
            const newHistory = await getMatchHistory(eventCode, match.number)
            setCommits(newHistory);
            setSelectedRecord(newHistory.length - 1);
        })()
    }, [visible, match])

    useEffect(() => {
        (async () => {
            if (!match || selectedRecord < 0) {
                setSheetData(undefined);
                return;
            }
            const url = `/event/${eventCode}/match/${commits[selectedRecord].split(":")[0].toLowerCase()}/history/${selectedRecord}/?embed=true`;
            const response = await fetch(url);
            const html = await response.text();
            setSheetData({ __html: html });
        })()
    }, [match, selectedRecord]);

    if(!match) {
        return <></>;
    }

    function handleClose() {
        setCommits([])
        close()
    }

    async function copyToEditor() {
        updateMatchDetails(await restoreMatchHistory(eventCode, match!.number, selectedRecord))
        handleClose()
    }

    return <Modal show={visible} onHide={handleClose} dialogClassName={"matchHistoryModal"} scrollable={true}>
        <Modal.Header closeButton>
            <Modal.Title>{t`Commit History for ${match.name}`}</Modal.Title>
        </Modal.Header>
        <Modal.Body>
            {t`Select Record`}
            <select className={"ml-2 w-50"} value={selectedRecord} onChange={(evt) => setSelectedRecord(parseInt((evt.target as HTMLSelectElement).value))}>
                {[...commits].reverse().map((c, idx) => <option value={commits.length - idx - 1} key={idx}>{c}</option>)}
            </select>
            <Button className={"ml-2"} variant={"success"} disabled={selectedRecord < 0} onClick={copyToEditor}>{t`Copy to Editor`}</Button>
            {sheetData ? <div className="scoresheetContainer" dangerouslySetInnerHTML={sheetData}/> : null}
        </Modal.Body>
    </Modal>
}