import {Alert, Button, Modal} from 'react-bootstrap';
import './DeauthNotifications.css'
import {useState} from "react";

export interface DeauthEvent {
    "ssid": string,
    "num": number,
    "code": string,
    "match": number,
    "victim": string,
    "last_seen": string,
    "active": boolean,
    "pkt_count": string,
    "matchTimeRemaining": string,
    "matchShortName": string,
    "team": number
}

export default function DeauthDetails({deauthEvents, hide} : {
    deauthEvents: Record<string, DeauthEvent[]>,
    hide: () => void
}) {
    return <Modal show onHide={hide} className={"text-dark"}>
        <Modal.Header closeButton>
            <Modal.Title>Deauth Events</Modal.Title>
        </Modal.Header>

        <Modal.Body>
            {Object.entries(deauthEvents).sort(([name1], [name2]) => name2.localeCompare(name1)).map(([name, entries]) => {
                return <>
                    <b>Match {name}</b>
                    {entries.map((e, idx) => <pre key={idx}>{JSON.stringify(e, undefined, 2)}</pre>)}
                </>
            })}
        </Modal.Body>
    </Modal>;
}