import {Button, Dropdown, DropdownButton, Form} from "react-bootstrap";

import { t } from 'ftc-common/i18n';
import {useCallback, useId, useState} from "react";
import {advanceToQuals, returnToPractice, setConfig, setTestMode, syncNow, testSync} from "./api/management";
import {endTimeout, fieldTimeout, showTimeout} from "./api/match";

import {useTimer} from "ftc-common/hooks";
import {useUniqueId} from "ftc-common/utils";
import {confirmDialog, messageDialog} from "first-common/dialogs";
import { EventSettings, MatchType, ScheduleUpdateSyncStatus, TimeoutData } from "../javaTypes";
import { ControlMatch } from "./connection";
import { SelectionState } from "ftc-common/javaTypes";

export default function Settings({settings, eventCode, isMeet, isArchived, showHelp, activeType, activeMatch,
                            syncStatus, timeoutData, resetElims, nowCallback, selectionState,
                            showDeauthDetails, isDualDivisionParent, matches, unsavedMatchCount} : {
    settings: Partial<EventSettings>,
    eventCode: string,
    isMeet: boolean,
    isArchived: boolean,
    showHelp: () => void,
    activeType: MatchType,
    activeMatch?: ControlMatch<any, any>,
    syncStatus: ScheduleUpdateSyncStatus,
    timeoutData: Partial<TimeoutData>,
    resetElims: () => void,
    nowCallback: () => number,
    selectionState?: SelectionState,
    showDeauthDetails?: () => void,
    isDualDivisionParent: boolean,
    matches: ControlMatch<any, any>[],
    unsavedMatchCount: number
}) {
    const setSetting = useCallback(async (key: string, value: any) => {
        await setConfig(eventCode, key, value)
    }, [])
    const testMode = activeType === 'TEST';
    const [connectionTestResponse, setConnectionTestResponse] = useState("");
    const [syncNowResponse, setSyncNowResponse] = useState("");
    const baseId = useId();

    const activeMatchRunning = activeMatch && activeMatch?.state !== 'REVIEW' && activeMatch?.state !== 'SUBMITTED'

    const now = nowCallback();
    // const isTimeoutRunning = timeoutData.activeTimeouts?.some(t => t.start + t.duration > now);
    // const canStartFieldTimeout = !isArchived && !activeMatchRunning && activeType === 'QUALS' && !isTimeoutRunning;
    // const canEndTimeout = !isArchived && isTimeoutRunning && activeType === 'QUALS';

    async function tryEndTimeout(code: string) {
        if (!await confirmDialog({
            label: t`End Timeout?`,
            text: t`Are you sure you want to end the timeout? This will silently end the timeout timer. This cannot be undone - 
                    the timer can only be restarted with a new 5:00 countdown.`
        })) {
            return;
        }
        await endTimeout(code);
    }

    const silently = `<strong><u>${t`silently`}</u></strong>`;
    const alwaysSilent = `<strong><u>${t`always silent`}</u></strong>`;
    const meetRankingsUniqueId = useUniqueId();

    const transitionTestMode = useCallback(async (eventCode: string, mode: boolean) => {
        // We only need to warn when _entering_ test mode. You can leave behind unsaved test matches without danger
        if(unsavedMatchCount > 0 && mode) {
            messageDialog({
                label: t`Incomplete Matches!`,
                text: t`There are ${unsavedMatchCount} incomplete matches! Please commit them before entering test mode.`,
            })
            return
        }
        await setTestMode(eventCode, mode)
    }, [unsavedMatchCount])

    const transitionToPractice = useCallback(async (eventCode: string) => {
        // We only need to warn when _entering_ practice mode. You can leave behind unsaved practice matches without danger
        if(unsavedMatchCount > 0) {
            messageDialog({
                label: t`Incomplete Matches!`,
                text: t`There are ${unsavedMatchCount} incomplete matches! Please commit them before returning to practice matches.`,
            })
            return
        }
        await returnToPractice(eventCode)
    }, [unsavedMatchCount])

    return <div>
        {isArchived ? <fieldset>
            <legend>{t`Event Archived`}</legend>
            {t`This event has been archived and uploaded to FIRST. If you need to make any changes, please contact FIRST event help.`}<button className={"btn btn-link"} onClick={showHelp}>{t`Contact Information`}</button>
        </fieldset> : null }
        <fieldset>
            <legend>{t`Active Match Schedule`}</legend>
            <Button className={"mr-2"} variant={isArchived || activeMatchRunning ? "light" : "success"} disabled={isArchived || activeMatchRunning} onClick={() => transitionTestMode(eventCode, !testMode)}>{testMode ? t`Exit Test Mode` : t`Enter Test Mode`}</Button>
            <Button className={"mr-2"} variant={isArchived || activeMatchRunning ? "light" : "success"} disabled={isArchived || activeMatchRunning || activeType !== 'PRACTICE'} title={activeType === 'TEST' ? t`Cannot advance to quals while in test mode` : undefined} onClick={() => advanceToQuals(eventCode)}>{t`Advance to Quals`}</Button>
            <Button className={"mr-2"} variant={isArchived || activeMatchRunning ? "light" : "success"} disabled={isArchived || activeMatchRunning || activeType !== 'QUALS'} title={activeType === 'TEST' ? t`Cannot return to practice while in test mode` : undefined} onClick={() => transitionToPractice(eventCode)}>{t`Return to Practice`}</Button>
        </fieldset>
        <fieldset>
            <legend>{t`Timing Controls`}</legend>
            {/*{fieldTimeoutBtn}*/}
            {/*<Button className={"mr-2"} variant={isTimeoutRunning ? "success" : "light"} disabled={!isTimeoutRunning} onClick={() => showTimeout(eventCode)}>{t`Show Timeout`}</Button>*/}
            {/*<Button className={"mr-2"} variant={isTimeoutRunning ? "success" : "light"} disabled={true} >{t`Silence Current Timeout`}</Button>*/}
            {/*<Button className={"mr-2"} variant={canEndTimeout ? "danger" : "light"} disabled={!canEndTimeout} hidden={activeType !== 'QUALS'} onClick={() => tryEndTimeout(eventCode)}>{t`End Timeout`}</Button>*/}
            {<div dangerouslySetInnerHTML={{__html: t`Timing still under development. All T206 and pre-violation G301 timers are started automatically and are ${alwaysSilent}`}}/>}
            {<div dangerouslySetInnerHTML={{__html: t`Expected start timers will be ${silently} ended if the next match is started. A running timer will not prevent match start - just make sure all teams are ready!`}}/>}

        </fieldset>
        <fieldset>
            <legend>{t`Live Scoring`}</legend>
            <Form.Check
                type={'checkbox'}
                label={t`Use Live Scoring`}
                checked={settings.liveScoring || false}
                disabled={isArchived}
                onChange={e => setSetting('liveScoring', e.target.checked)}
                id={useUniqueId()}
            />
            <Form.Check
                type={'checkbox'}
                label={t`Require Referee Init Submit Before Match Start`}
                checked={settings.waitForInitSubmit || false}
                onChange={e => setSetting('waitForInitSubmit', e.target.checked)}
                id={useUniqueId()}
            />
            <Form.Check
                type={'checkbox'}
                label={<>{t`Enable Penalty Referee Tablets`} <i className={"fa fa-question-circle"} title={t`Requires all four referees actively use their tablets each match.`}/></>}
                checked={settings.penaltyTabletsEnabled || false}
                disabled={isArchived || activeMatchRunning}
                title={activeMatchRunning ? t`Cannot enable/disable penalty tablet during a match` : undefined}
                onChange={e => setSetting('penaltyTabletsEnabled', e.target.checked)}
                id={useUniqueId()}
            />
            <>{t`Enable External Match Control (Beta)`} <i className={"fa fa-question-circle"} title={t`Allows basic match control from other pages.`}/></>
            <select
                value={settings.hrControl || 'NONE'}
                onChange={e => setSetting('hrControl', e.target.value)}
                id={useUniqueId()}>
                <option value={'NONE'}>{t`None`}</option>
                <option value={'RANDOM'}>{t`Randomization`}</option>
                <option value={'START'}>{t`Match Start`}</option>
                <option value={'START_RANDOM'}>{t`Randomization & Match Start`}</option>
                <option value={'FULL'}>{t`Full Control`}</option>
            </select>
            <Form.Check
                type={'checkbox'}
                label={t`Allow External Randomization`}
                checked={settings.externalRandom}
                disabled={isArchived}
                onChange={e => setSetting('externalRandom', e.target.checked)}
                id={useUniqueId()}
            />
        </fieldset>
        <fieldset>
            <legend>{t`Control Page Appearance`}</legend>
            <Form.Check
                type={'checkbox'}
                label={t`Flip Alliances (Red on Left)`}
                checked={settings.flipControl || false}
                onChange={e => setSetting('flipControl', e.target.checked)}
                id={useUniqueId()}
            />
            {t`Score tab contrast: `}
            <select value={settings.controlContrast || 'standard'}
                onChange={e => setSetting('controlContrast', e.target.value)}>
                <option value="standard">Standard</option>
                <option value="high">High</option>
                <option value="max">Max</option>
                <option value="dark">Dark Mode</option>
            </select>
        </fieldset>
        { isMeet ? <fieldset>
            <legend>{t`Scoring/Pit Display Options`}</legend>
            <Form.Check
                type={'checkbox'}
                label={t`Show Event Rankings in addition to League Rankings.`}
                checked={settings.showMeetRankings}
                onChange={e => setSetting('showMeetRankings', e.target.checked)}
                id={meetRankingsUniqueId}
            />
        </fieldset> : null }
        <fieldset>
            <legend>{t`Sync Settings`}</legend>
            {t`Sync Delay: `}
            <i className="fas fa-question-circle"
               title={t`Delay between match commit and when the match data is sent to FIRST. 10s is the default and recommended checked. This does not affect 3rd party API clients running locally.`}></i>
            <select value={settings.syncDelay}
                    onChange={(e) => setSetting('syncDelay', e.target.value)}>
                <option value="10">{t`10 seconds`}</option>
                <option value="30">{t`30 seconds`}</option>
                <option value="60">{t`1 minute`}</option>
                <option value="300">{t`5 minutes`}</option>
            </select><br/>
            Last successful sync: {syncStatus.lastSyncTime > 0 ? new Date(syncStatus.lastSyncTime).toLocaleTimeString() : t`N/A`}<br/>
            <Button className={"mt-2"} variant={"success"} onClick={async () => setConnectionTestResponse(await testSync(eventCode))}>{t`Test Connection to HQ`}</Button> <span>{connectionTestResponse}</span><br/>
            <Button className={"mt-2"} variant={"success"} onClick={async () => setSyncNowResponse(await syncNow(eventCode))}>{t`Sync Now`}</Button> <span>{syncNowResponse}</span>
        </fieldset>
        {settings.allowPlayoffOverrides ? <fieldset>
            <legend>{t`Playoff Configuration Overrides`}</legend>
            <label htmlFor={`${baseId}-playoff-type`}>{t`Playoff type:`}&nbsp;</label>
            <select value={settings.playoffTypeOverride} id={`${baseId}-playoff-type`} disabled={isArchived || activeType == 'ELIMS' || !!selectionState}
                    onChange={e => {
                        setSetting('playoffTypeOverride', e.target.value)
                        if (settings.allianceCountOverride == 6 && e.target.value === 'SINGLE_ELIMINATION') {
                            setSetting('allianceCountOverride', 0);
                        }
                    }}>
                <option value="">(default)</option>
                <option value="DOUBLE_ELIMINATION">Double Elimination</option>
                <option value="DOUBLE_ELIMINATION_WITH_FINALS">Double Elimination With Finals (FRC-Style)</option>
                <option value="SINGLE_ELIMINATION">Single Elimination</option>
            </select><br/>
            <label htmlFor={`${baseId}-alliance-count`}>{t`Alliance count:`}&nbsp;</label>
            <select value={settings.allianceCountOverride} id={`${baseId}-alliance-count`} disabled={isArchived || activeType == 'ELIMS' || !!selectionState}
                    onChange={e => setSetting('allianceCountOverride', e.target.value)}>
                <option value="0">(default)</option>
                <option value="2">2</option>
                <option value="4">4</option>
                <option value="6" disabled={settings.playoffTypeOverride == 'SINGLE_ELIMINATION'}>6</option>
                <option value="8">8</option>
            </select><br/>
            <label htmlFor={`${baseId}-teams-per-alliance`}>{t`Teams per alliance:`}&nbsp;</label>
            <select value={`${settings.teamsPerAllianceOverride}-${settings.allowBackupsOverride}`} id={`${baseId}-teams-per-alliance`} disabled={isArchived || activeType == 'ELIMS' || !!selectionState}
                    onChange={e => {
                        const parts = e.target.value.split('-');
                        setSetting('teamsPerAllianceOverride', parts[0])
                        setSetting('allowBackupsOverride', parts[1])
                    }}>
                <option value="0-">(default)</option>
                <option value="2-false">2</option>
                <option value="2-true">2 (with backups)</option>
                <option value="3-false">3</option>
            </select>
        </fieldset> : null}
        <fieldset>
            <legend>{t`Danger Zone`}</legend>
            <Button className={"mt-2 mr-2"} variant={"danger"} onClick={() => resetElims()} disabled={(activeType !== 'ELIMS' && !selectionState) || isArchived || (activeType === 'ELIMS' && matches.some(m => m.state === "COMMITTED"))}>{isDualDivisionParent ? t`Reset Playoff Matches` : t`Reset Alliance Selection`}</Button>
            {showDeauthDetails ? <Button className={"mt-2 mr-2"} variant={"warning"} onClick={showDeauthDetails}>{t`Deauth Event Details`}</Button> : showDeauthDetails}
        </fieldset>
    </div>;
}