import MatchControl from "./MatchControl";
import ErrorBoundary from "../LocalErrorBoundary";
import { createRoot } from "react-dom/client";
import {QueryClientProvider} from "@tanstack/react-query";
import {queryClient} from "./connection";
import {parseMatchTiming} from "ftc-common/utils";

const root = createRoot(document.getElementById("matchControl"));

root.render(<ErrorBoundary>
    <QueryClientProvider client={queryClient}>
        <MatchControl
            eventCode={window.eventCode}
            isMeet={window.isMeet}
            fieldCount={window.fieldCount}
            pinField={window.pinField}
            isDualDivisionParent={window.isDualDivisionParent}
            isDivision={window.isDivision}
            divisions={window.divisions}
            timing={parseMatchTiming(window.matchTiming)}
        />
    </QueryClientProvider>
</ErrorBoundary>)
