import {t} from "ftc-common/i18n";

import {useEffect, useRef, useState} from "react";
import {Button, ButtonProps, Card, Form, Spinner} from "react-bootstrap";
import {editMatch, getMatchScore, unsavedEdit} from "./api/match";

import "./ScoreEdit.css";
import MatchHistoryDialog from "./MatchHistoryDialog";
import {useUniqueId} from "ftc-common/utils";
import {DecodeInput, DecodeInputBreakdown, ScoreDetailType, ScoreType, Randomization} from "./seasons/Decode";
import {Alliance} from "../ref/Ref";
import {EventSettings, Match, MatchState, MatchType} from "../javaTypes";
import {abortMatch, ControlMatch} from "./connection";
import {confirmDialog} from "first-common/dialogs";

type ScoreTypeSetValue = <K extends keyof ScoreType>(key: K, value: ScoreType[K]) => void
type EnrichedScoreType = ScoreType & { breakdown?: ScoreDetailType }
const RED_CARD = 2;
const YELLOW_CARD = 1;

// @ts-expect-error xs is not an official size
const ButtonXs = (props: Omit<ButtonProps, 'size'>) => <Button size={"xs"} {...props}/>

function AllianceCards({match, isElims, alliance, cardCarries, detailAlliance, right, color, updateScore, readOnly} :{
    match:  Match | undefined, isElims: boolean, alliance?: Alliance<ScoreType>, cardCarries?: {team1?: string[], team2?: string[]},
    detailAlliance?: ScoreType, right: boolean, color: string, updateScore: ScoreTypeSetValue, readOnly: boolean
}) {
    return <div dir={right ? 'ltr' : 'rtl'} className={`allianceCards ${right ? 'right' : 'left'} ${isElims ? "elims" : ""}`}>
        <table>
        <tbody>
            <tr>
                <td>{color}</td>
                {isElims ? <td title={t`Not Playing`}>NP</td> : <td title={t`No ROBOT. (With Team Member present)`}>NR</td>}
                <td title={t`DISQUALIFIED`}>DQ</td>
                <td title={t`YELLOW CARD. Check Y & R if 2nd+ YELLOW CARD.`}>Y</td>
                <td title={t`RED CARD.`}>R</td>
            </tr>
            {([1, 2, 3] as const).map(i => {
                // We never have card or DQ related fields for i == 3, so we use the card data from team 1
                const cardIdx = isElims || i == 3 ? 1 : i;
                const carries = cardCarries?.[`team${cardIdx}`];
                const hasCarry = carries && carries.length > 0;
                // need to check if we are editing a card - it needs to be removable
                const isOnlyCarrySource = carries && carries.filter(x => x !== match?.shortName).length === 0;
                const redChecked = ((detailAlliance?.[`card${cardIdx}`] || 0) & RED_CARD) !== 0;
                const yellowChecked = ((detailAlliance?.[`card${cardIdx}`] || 0) & YELLOW_CARD) !== 0;
                return !alliance || alliance[`team${i}`] ? <tr key={i}>
                    <td style={{backgroundColor: hasCarry ? 'yellow' : 'transparent'}}
                        title={hasCarry ? t`Earned cards in ${carries}` : ''}>{alliance?.[`team${i}Display`]}</td>
                    {isElims ? <>
                        <td><input type="checkbox" checked={detailAlliance?.[`noshow${i}`] === 1} onChange={(e) => updateScore(`noshow${i}`, (e.target as HTMLInputElement).checked ? 1 : 0)} disabled={readOnly}/></td>
                        <td><input type="checkbox" checked={detailAlliance?.dq1 === 1} onChange={(e) => updateScore(`dq1`, (e.target as HTMLInputElement).checked ? 1 : 0)} disabled={readOnly || ((detailAlliance?.card1 ?? 0) & RED_CARD) !== 0}/></td>
                    </> : <>
                        <td><input type="checkbox" checked={(detailAlliance?.[`noshow${i}`] ?? 0) > 0} onChange={(e) => updateScore(`noshow${i}`, (e.target as HTMLInputElement).checked ? 2 : 0)} disabled={readOnly} /></td>
                        <td><input type="checkbox" checked={detailAlliance?.[`dq${cardIdx}`] === 1} onChange={(e) => {
                            updateScore(`dq${cardIdx}`, (e.target as HTMLInputElement).checked ? 1 : 0)
                            // noshow == 1 means DQ + no show, so if clearing the DQ, downgrade the noshow to a "regular" noshow
                            if(detailAlliance?.[`noshow${cardIdx}`] == 1) {
                                updateScore(`noshow${cardIdx}`, 2)
                            }
                        }} disabled={readOnly || redChecked } /></td>
                    </>}
                    <td><input type="checkbox" checked={yellowChecked} onChange={(e) => {
                        let newCard = (e.target as HTMLInputElement).checked ? detailAlliance![`card${cardIdx}`] | YELLOW_CARD : detailAlliance![`card${cardIdx}`] & ~YELLOW_CARD;
                        if ((newCard & YELLOW_CARD) && hasCarry && !isOnlyCarrySource) {
                            newCard |= RED_CARD;
                        }
                        updateScore(`card${cardIdx}`, newCard);
                    }} disabled={readOnly} /></td>
                    <td><input type="checkbox" checked={((detailAlliance?.[`card${cardIdx}`] || 0) & RED_CARD) !== 0} onChange={(e) => {
                        let newCard = (e.target as HTMLInputElement).checked ? detailAlliance![`card${cardIdx}`] | RED_CARD : detailAlliance![`card${cardIdx}`] & ~RED_CARD;
                        if ((newCard & YELLOW_CARD) && hasCarry && !isOnlyCarrySource) {
                            newCard |= RED_CARD;
                        }
                        updateScore(`card${cardIdx}`, newCard);
                    }} disabled={readOnly || (yellowChecked && hasCarry && !isOnlyCarrySource)} title={(yellowChecked && hasCarry && !isOnlyCarrySource) ? t`Because of prior CARD, any YELLOW CARD in this MATCH must lead to a RED CARD. To remove the RED CARD, first remove the YELLOW CARD.` : ''}/></td>
                </tr> : null
            })}
        </tbody>
        </table>
    </div>
}

function Breakdown({score, breakdown, showAdjust, other, updateScore, isPlayoff}: {
    score?: ScoreType, breakdown?: ScoreDetailType, showAdjust: boolean, other?: ScoreType, updateScore: ScoreTypeSetValue, isPlayoff: boolean
}) {
    const tiebreakRule = 'T705.B';
    const simultaneousDqRule = 'T705.C';
    const adjustUniqueId = useUniqueId();
    return <>
        <legend>{t`Score Breakdown`}</legend>
        <DecodeInputBreakdown score={score} breakdown={breakdown} other={other} isPlayoff={isPlayoff} />
        {showAdjust ? <Card bg={"warning"} style={{width: '250px'}}>
            <Card.Body>
                <Card.Title style={{textAlign: 'center'}}>{t`Adjust`}</Card.Title>
                <Card.Text>
                    {t`Use this field to give 1 point to the ALLIANCE that was DISQUALIFIED second (the winner by ${tiebreakRule}), unless it was simultaneous (${simultaneousDqRule})`}
                </Card.Text>
                <Form.Check
                    type={'checkbox'}
                    label={t`Tiebreak Point`}
                    checked={score!.adjust > 0}
                    onChange={e => updateScore('adjust', e.target.checked ? 1 : 0)}
                    id={adjustUniqueId}
                />
            </Card.Body>
        </Card> : null}
    </>;
}

const readOnlyStates: (MatchState | undefined)[] = [MatchState.AUTO, MatchState.TELEOP, MatchState.REVIEW]

interface MatchDetails {
    number: number,
    type: MatchType,
    red: ScoreType,
    blue: ScoreType,
    redBreakdown: ScoreDetailType,
    blueBreakdown: ScoreDetailType,
    redCardCarries1?: string[],
    redCardCarries2?: string[],
    blueCardCarries1?: string[],
    blueCardCarries2?: string[],
    historySize?: number,
    redTotal: number,
    blueTotal: number,
}

export default function ScoreEdit({isArchived, showHelp, settings, match, eventCode, openMatchForEditing, closeMatch, lockoutMatch, commitMatch, postMatch, active, activeMatchRunning}:
                          {isArchived?: boolean, showHelp?: () => void, settings: Partial<EventSettings>, match?: ControlMatch<ScoreType, ScoreDetailType>, eventCode: string,
                              openMatchForEditing?: (number: number) => void, closeMatch?: () => void, lockoutMatch?: (number: number) => Promise<boolean>,
                              commitMatch?: (number: number, verifyCommit: boolean) => void, postMatch?: (number: number) => Promise<void>,
                              active?: boolean, activeMatchRunning?: boolean}) {
    const [loading, setLoading] = useState(!active);
    const [matchDetails, setMatchDetails] = useState<MatchDetails>();
    const [hasEdits, setHasEdits] = useState(false);
    const [reload, setReload] = useState(false);
    const prevState = useRef<MatchState>();
    const [showMatchHistory, setShowMatchHistory] = useState(false);

    useEffect(() => {
        (async () => {
            if(active || !match?.number) {
                return;
            }
            if(matchDetails?.number === match.number && matchDetails?.type === match.type && !reload && readOnlyStates.includes(prevState.current) === readOnlyStates.includes(match.state)) {
                prevState.current = match.state;
                return;
            }

            if(!readOnlyStates.includes(match.state)) {
                setLoading(true)
                setMatchDetails(await getMatchScore(eventCode, match.number))
                setLoading(false)
                setReload(false)
                setHasEdits(false)
            } else {
                setMatchDetails(undefined)
                setLoading(false)
            }
        })()
    }, [match?.type, match?.number, match?.state, reload]);

    if(!active && !match) {
        return null;
    }

    if(loading) {
        return <div>Loading match data...<Spinner animation={"border"}/></div>
    }

    /**
     * If alliance === 'both', the first value provided is red, the second is blue. This allows updating both at once without worrying about the order the server handles them.
     */
    function updateScore<K extends keyof ScoreType>(alliance: 'red' | 'blue', field: K, value: ScoreType[K]): Promise<void>;
    function updateScore<K extends keyof ScoreType>(alliance: 'both', field: K, redValue: ScoreType[K], blueValue: ScoreType[K]): Promise<void>;
    async function updateScore<K extends keyof ScoreType>(alliance: 'red' | 'blue' | 'both', field: K, value: ScoreType[K], value2?: ScoreType[K]) {
        const src2 = alliance === 'both'
                ? { red: Object.assign({}, matchDetails!.red, { [field]: value}),
                        blue: Object.assign({}, matchDetails!.blue, { [field]: value2})}
                : { [alliance]: Object.assign({}, matchDetails![alliance], { [field]: value }) };
        const payload = Object.assign({},
            { red: matchDetails!.red, blue: matchDetails!.blue },
            src2
        )
        // RED CARD -> DISQUALIFICATION, cards are never set together
        if ((alliance === 'red' || alliance === 'blue')) {
            if (field === 'card1' && (value as number) > 1) {
                payload[alliance].dq1 = 1;
            }
            if (field === 'card2' && (value as number) > 1) {
                payload[alliance].dq2 = 1;
            }
            if ((!payload.red.dq1 || !payload.blue.dq1) && (payload.blue.adjust || payload.red.adjust)) {
                payload.red.adjust = 0;
                payload.blue.adjust = 0;
            }
        }

        // todo be smarter and reset back to false if unchanged
        setHasEdits(true)
        setMatchDetails(await unsavedEdit(eventCode, match!.number, payload))
    }

    async function editScore() {
        await editMatch(eventCode, match!.number, { red: matchDetails!.red, blue: matchDetails!.blue })
        setHasEdits(false)
    }

    async function forceEdit() {
        if(!await confirmDialog({
            label: t`Override Referees?`,
            text: t`This will lock out referee devices from submitting any more scores. Any unsubmitted changes on their devices will be lost.`,
            buttonText: t`Lockout`
        })) {
            return;
        }
        await lockoutMatch!(match!.number)
    }

    async function commitScore() {
        if(hasEdits || match!.state !== 'SUBMITTED') {
            await editScore()
            commitMatch!(match!.number, false)
        } else {
            commitMatch!(match!.number, true)
        }
    }

    let readOnly = active || false;
    let topBanner;
    if (isArchived) {
        readOnly = true;
        topBanner = <div className={"editBanner"}>{t`This event has been archived and uploaded to FIRST. If you need to make any changes, please contact FIRST event help.`}<button className={"btn btn-link"} onClick={showHelp}>{t`Contact Information`}</button> </div>
    } else if (active || !match) {
        if(match && match.state !== 'AUTO' && match.state !== 'TELEOP' && openMatchForEditing) {
            topBanner = <div className={"editBanner"} style={{fontSize: '20px'}}>{t`Showing scores for previous match.  Scores will clear at start of next match.`} <ButtonXs className={"ml-2"} style={{fontSize: '20px'}} variant={"info"} onClick={() => openMatchForEditing(match.number)}>To Edit Click Here</ButtonXs> </div>
        }
    } else if(!readOnlyStates.includes(match.state)) {
        topBanner = <div className={"editBanner p-1"}>
            <ButtonXs className="mx-2" variant="primary" disabled={match.type === 'TEST' || matchDetails?.historySize === 0} onClick={() => setShowMatchHistory(true)}>{t`View History`}</ButtonXs>
            <ButtonXs className="mx-2" variant="primary" disabled={!hasEdits} onClick={() => setReload(true)}>{t`Cancel Edits`}</ButtonXs>
            <ButtonXs className="mx-2" variant="primary" disabled={!hasEdits} onClick={() => editScore()}>{t`Save Edits`}</ButtonXs>
            <ButtonXs className="mx-2" variant="primary" disabled={match.state === 'COMMITTED' && !hasEdits} onClick={() => commitScore()}>{t`Commit`}</ButtonXs>
            {closeMatch && match.seriesDescription?.matchesToWin == 0 ?
                <ButtonXs className="mx-2" variant="primary" disabled={hasEdits} onClick={() => closeMatch()}>{t`Done Editing`}</ButtonXs> :
                <ButtonXs className="mx-2" variant="primary" disabled={match.state !== 'COMMITTED' || activeMatchRunning || hasEdits} onClick={() => postMatch!(match.number)}>{t`Post Results`}</ButtonXs>}
            {match.state == "SUBMITTED" ? <ButtonXs className="mx-2" variant="danger" disabled={activeMatchRunning} onClick={() => abortMatch(eventCode, match.number, true)}>{t`Discard Match`}</ButtonXs> : null}
        </div>
    } else {
        readOnly = true;
        const missingPeople = [];
        if(!match.red.scoringStatus.reviewSubmitted) {
            missingPeople.push(t`Red Scoring`);
        }
        if(settings.penaltyTabletsEnabled && !match.red.penaltyStatus.reviewSubmitted) {
            missingPeople.push(t`Red Penalty`);
        }
        if(!match.blue.scoringStatus.reviewSubmitted) {
            missingPeople.push(t`Blue Scoring`);
        }
        if(settings.penaltyTabletsEnabled && !match.blue.penaltyStatus.reviewSubmitted) {
            missingPeople.push(t`Blue Penalty`);
        }
        if(missingPeople.length === 0) {
            missingPeople.push(t`HR`);
        }

        const forceEditButton = <ButtonXs className={"ml-2"} style={{fontSize: '20px'}} variant={"danger"} onClick={() => forceEdit()}>Force Edit</ButtonXs>;
        const missingLabel = missingPeople.join(', ')
        topBanner = <div className={"editBanner"} style={{fontSize: '20px'}}>{t`Waiting for referees (${missingLabel}) to submit scores.`} {match.state === "REVIEW" ? forceEditButton : null} </div>
    }

    const redScoreObj = matchDetails ? matchDetails.red : match?.red?.scores;
    const blueScoreObj = matchDetails ? matchDetails.blue : match?.blue?.scores;
    const redBreakdown = matchDetails ? matchDetails.redBreakdown : match?.red?.breakdown;
    const blueBreakdown = matchDetails ? matchDetails.blueBreakdown : match?.blue?.breakdown;

    const redCardCarries = matchDetails ? { team1: matchDetails.redCardCarries1, team2: matchDetails.redCardCarries2 } : match?.red?.cardCarries;
    const blueCardCarries = matchDetails ? { team1: matchDetails.blueCardCarries1, team2: matchDetails.blueCardCarries2 } : match?.blue?.cardCarries;

    let redTotal = matchDetails?.redTotal ?? (redScoreObj ? redScoreObj.scoredPoints + blueScoreObj!.penaltyPoints - (match!.state !== 'AUTO' ? 0 : redScoreObj.teleopToSubtractFromAuto) - (match!.state !== 'AUTO' && match!.state !== 'TELEOP' ? 0 : redScoreObj.teleopToSubtractFromInMatch) : 0)
    let blueTotal = matchDetails?.blueTotal ?? (blueScoreObj ? blueScoreObj.scoredPoints + redScoreObj!.penaltyPoints - (match!.state !== 'AUTO' ? 0 : blueScoreObj.teleopToSubtractFromAuto) - (match!.state !== 'AUTO' && match!.state !== 'TELEOP' ? 0 : blueScoreObj.teleopToSubtractFromInMatch) : 0)

    const isElims = match?.type === 'ELIMS';
    const showAdjust = isElims && (redScoreObj?.dq1 || 0) > 0 && (blueScoreObj?.dq1 || 0) > 0;

    return <div className={`scoreEditContent contrast-${settings.controlContrast}`}>
        {topBanner}

        <div className={"scoreEditBody"}>
            <div className={"matchOverview"}>
                <span className={"name"}>{match ? match.name : t`No Active Match`}</span>
                <hr/>
                <span className={"totalScore"}>{settings.flipControl ? redTotal : blueTotal}</span>
                <span className={"totalScore"}>{settings.flipControl ? blueTotal : redTotal}</span>
                {match?.hrReview && active ? <span className={"reviewBanner"}>{t`Referee Review`}</span> : null }

                <AllianceCards match={match} isElims={isElims} color={t`Red`} cardCarries={redCardCarries} alliance={match?.red} detailAlliance={redScoreObj} right={!settings.flipControl} updateScore={(field, value) => updateScore('red', field, value)} readOnly={readOnly} />
                <AllianceCards match={match} isElims={isElims} color={t`Blue`} cardCarries={blueCardCarries} alliance={match?.blue} detailAlliance={blueScoreObj} right={!!settings.flipControl} updateScore={(field, value) => updateScore('blue', field, value)} readOnly={readOnly} />

                <Randomization random={match?.randomization} />

                <fieldset className={`scoreBreakdown ${settings.flipControl ? 'left' : 'right'}`}>
                    <Breakdown score={redScoreObj} other={blueScoreObj} breakdown={redBreakdown} showAdjust={showAdjust} updateScore={(field, value) => updateScore('red', field, value)} isPlayoff={isElims} />
                </fieldset>
                <fieldset className={`scoreBreakdown ${settings.flipControl ? 'right' : 'left'}`}>
                    <Breakdown score={blueScoreObj} other={redScoreObj} breakdown={blueBreakdown} showAdjust={showAdjust} updateScore={(field, value) => updateScore('blue', field, value)} isPlayoff={isElims} />
                </fieldset>
            </div>
            <div dir={settings.flipControl ? 'ltr' : 'rtl'}>
                <div className={`scoreSection red ${settings.flipControl ? 'left' : 'right'}`}>
                    <DecodeInput color={"Red"} readOnly={readOnly} random={match?.randomization} details={redScoreObj} otherDetails={blueScoreObj} teams={([1,2,3] as const).map(x => match?.red[`team${x}`])} otherTeams={([1,2,3] as const).map(x => match?.blue[`team${x}`])} updateScore={(field, value) => updateScore('red', field, value)} updateBothScores={(field, red, blue) => updateScore('both', field, red, blue)} isPlayoff={isElims} />
                </div>
                <div className={`scoreSection blue ${settings.flipControl ? 'right' : 'left'}`}>
                    <DecodeInput color={"Blue"} readOnly={readOnly} random={match?.randomization} details={blueScoreObj} otherDetails={redScoreObj} teams={([1,2,3] as const).map(x => match?.blue[`team${x}`])} otherTeams={([1,2,3] as const).map(x => match?.red[`team${x}`])}  updateScore={(field, value) => updateScore('blue', field, value)} updateBothScores={(field, red, blue) => updateScore('both', field, red, blue)} isPlayoff={isElims} />
                </div>
            </div>
        </div>
        <MatchHistoryDialog visible={showMatchHistory} close={() => setShowMatchHistory(false)} match={match} eventCode={eventCode} updateMatchDetails={(data) => {
            setMatchDetails(data)
            setHasEdits(true)
        }}/>
    </div>

}