import {BracketStyle} from "ftc-common/javaTypes";
import {PermissiveURLSearchParams} from "ftc-common/utils";
import {messageDialog} from "first-common/dialogs";
import {t} from "ftc-common/i18n";
import {DisplayConfig} from "ftc-common/displays/Config";

export async function showSponsors(eventCode: string, field?: number) {
    await fetch(`/event/${eventCode}/control/sponsors/`, {
        method: "POST",
        body: field ? PermissiveURLSearchParams({ field }) : null
    })
}

export async function showBracket(eventCode: string, style: BracketStyle, field?: number) {
    const params: {
        style?: BracketStyle,
        field?: number
    } = {}
    if(style) {
        params.style = style
    }
    if(field) {
        params.field = field
    }
    await fetch(`/event/${eventCode}/control/bracket/`, {
        method: "POST",
        body: PermissiveURLSearchParams(params)
    })
}

