export async function showOnlineResults(eventCode: string, field?: number) {
    const res = await fetch(`/event/${eventCode}/control/command/online/`, {
        method: "POST",
        body: field ? PermissiveURLSearchParams({ field }) : null
    })
    if (!res.ok || (await res.text()) !== 'OK') {
        messageDialog({
            label: t`Unable to Show Online Results`,
            text: t`Cannot show online information when sync is disconnected`
        })
    }
}

